parameters.global_declarations:
#include <Wire.h>

const uint8_t g_mpu6050_addr = 0x68;

typedef struct
{
  int16_t ax;
  int16_t ay;
  int16_t az;

  int16_t gx;
  int16_t gy;
  int16_t gz;
} MPU6050_Data;

MPU6050_Data g_mpu6050_data;

float g_accel_scale = 16384.0f;
float g_gyro_scale  = 131.0f;

uint8_t g_prev_accel_config = 0xFF;
uint8_t g_prev_gyro_config  = 0xFF;

static void g_mpu6050_read(MPU6050_Data* data)
{
  uint8_t buf[14];

  Wire.beginTransmission(g_mpu6050_addr);
  Wire.write(0x3B);
  Wire.endTransmission(false);

  Wire.requestFrom((int)g_mpu6050_addr, 14);

  if (Wire.available() < 14) {
    return;
  }

  for (int i = 0; i < 14; i++) {
    buf[i] = Wire.read();
  }

  data->ax = (int16_t)((buf[0] << 8) | buf[1]);
  data->ay = (int16_t)((buf[2] << 8) | buf[3]);
  data->az = (int16_t)((buf[4] << 8) | buf[5]);

  data->gx = (int16_t)((buf[8] << 8) | buf[9]);
  data->gy = (int16_t)((buf[10] << 8) | buf[11]);
  data->gz = (int16_t)((buf[12] << 8) | buf[13]);
}

parameters.init_code:
Wire.begin();

delay(100);

Wire.beginTransmission(g_mpu6050_addr);
Wire.write(0x6B);
Wire.write(0x00);
Wire.endTransmission();

Wire.beginTransmission(g_mpu6050_addr);
Wire.write(0x1C);
Wire.write(0x00);
Wire.endTransmission();

Wire.beginTransmission(g_mpu6050_addr);
Wire.write(0x1B);
Wire.write(0x00);
Wire.endTransmission();

g_prev_accel_config = 0x00;
g_prev_gyro_config  = 0x00;

parameters.step_code:
uint8_t accel_config;
uint8_t gyro_config;

/* Accelerometer range */

if ((int)inputs[0] == 2) {
  accel_config = 0x00;
  g_accel_scale = 16384.0f;
}
else if ((int)inputs[0] == 4) {
  accel_config = 0x08;
  g_accel_scale = 8192.0f;
}
else if ((int)inputs[0] == 8) {
  accel_config = 0x10;
  g_accel_scale = 4096.0f;
}
else {
  accel_config = 0x18;
  g_accel_scale = 2048.0f;
}

/* Gyroscope range */

if ((int)inputs[1] == 250) {
  gyro_config = 0x00;
  g_gyro_scale = 131.0f;
}
else if ((int)inputs[1] == 500) {
  gyro_config = 0x08;
  g_gyro_scale = 65.5f;
}
else if ((int)inputs[1] == 1000) {
  gyro_config = 0x10;
  g_gyro_scale = 32.8f;
}
else {
  gyro_config = 0x18;
  g_gyro_scale = 16.4f;
}

/* 設定変更時のみ書き込み */

if (accel_config != g_prev_accel_config)
{
  Wire.beginTransmission(g_mpu6050_addr);
  Wire.write(0x1C);
  Wire.write(accel_config);
  Wire.endTransmission();

  g_prev_accel_config = accel_config;
}

if (gyro_config != g_prev_gyro_config)
{
  Wire.beginTransmission(g_mpu6050_addr);
  Wire.write(0x1B);
  Wire.write(gyro_config);
  Wire.endTransmission();

  g_prev_gyro_config = gyro_config;
}

/* データ取得 */

g_mpu6050_read(&g_mpu6050_data);

/* 出力 */

const float GRAVITY = 9.80665f;

outputs[0] = (float)g_mpu6050_data.ax / g_accel_scale * GRAVITY;
outputs[1] = (float)g_mpu6050_data.ay / g_accel_scale * GRAVITY;
outputs[2] = (float)g_mpu6050_data.az / g_accel_scale * GRAVITY;

outputs[3] = (float)g_mpu6050_data.gx / g_gyro_scale;
outputs[4] = (float)g_mpu6050_data.gy / g_gyro_scale;
outputs[5] = (float)g_mpu6050_data.gz / g_gyro_scale;
